// Re-genera SOLO los chunks de prompt/personalidad/conocimiento
const body = $('Webhook omghat1').item.json.body;
const slug = body.agent_id;
const agentName = body.agent_name;
const tone = body.tone;
const prompt = body.prompt || '';

function splitText(texto, maxLen) {
  const partes = [];
  let inicio = 0;
  while (inicio < texto.length) {
    let fin = inicio + maxLen;
    if (fin >= texto.length) { partes.push(texto.substring(inicio).trim()); break; }
    let corte = texto.lastIndexOf(' ', fin);
    if (corte <= inicio) corte = fin;
    partes.push(texto.substring(inicio, corte).trim());
    inicio = corte + 1;
  }
  return partes.filter(p => p.length > 0);
}

const chunks = [];

// Identidad
chunks.push({
  text: `IDENTIDAD DEL NEGOCIO: ${agentName}. ${prompt.substring(0, 300).replace(/\n/g, ' ')}`,
  id: `identidad_${slug}_001`,
  tipo: 'identidad',
  categoria: 'identidad',
  relevancia: 1.0
});

// Secciones del prompt
const seccionRegex = /(?:🟢\s*)?\d+\.\s*([^\n]+)([\s\S]*?)(?=(?:🟢\s*)?\d+\.|$)/g;
let secMatch;
const secciones = [];
while ((secMatch = seccionRegex.exec(prompt)) !== null) {
  secciones.push({ titulo: secMatch[1].trim(), contenido: secMatch[2].trim() });
}

if (secciones.length > 0) {
  secciones.forEach((sec, i) => {
    if (sec.contenido.length < 20) return;
    splitText(sec.contenido, 600).forEach((parte, k) => {
      chunks.push({
        text: `${sec.titulo.toUpperCase()}: ${parte}`,
        id: `conocimiento_${slug}_sec${String(i+1).padStart(2,'0')}_${String(k+1).padStart(2,'0')}`,
        tipo: 'conocimiento',
        categoria: 'conocimiento',
        relevancia: 0.95
      });
    });
  });
} else {
  const parrafos = prompt.split(/\n{2,}/).map(s => s.trim()).filter(s => s.length > 30);
  parrafos.forEach((parr, i) => {
    splitText(parr, 600).forEach((parte, k) => {
      chunks.push({
        text: parte,
        id: `conocimiento_${slug}_p${String(i+1).padStart(2,'0')}_${String(k+1).padStart(2,'0')}`,
        tipo: 'conocimiento',
        categoria: 'conocimiento',
        relevancia: 0.9
      });
    });
  });
}

// Tono
const tonoDesc = {
  friendly: 'Tutea, sé cálido y cercano. Emojis con moderación.',
  formal: 'Trata de usted, profesional. Sin emojis.',
  casual: 'Relajado, emojis, coloquial.',
};
chunks.push({
  text: `PERSONALIDAD Y TONO: ${tone}. ${tonoDesc[tone] || tonoDesc.friendly}`,
  id: `personalidad_${slug}_001`,
  tipo: 'personalidad',
  categoria: 'personalidad',
  relevancia: 1.0
});

// Conversation examples
const examples = body.conversation_examples || [];
examples.forEach((ex, i) => {
  if (!ex.userMessage || !ex.agentResponse) return;
  chunks.push({
    text: `EJEMPLO DE CONVERSACIÓN: Cliente: ${ex.userMessage} / Agente: ${ex.agentResponse}`,
    id: `ejemplo_${slug}_${String(i+1).padStart(3,'0')}`,
    tipo: 'ejemplo_positivo',
    categoria: 'ejemplo_positivo',
    relevancia: 0.95
  });
});

return chunks.map(c => ({ json: { ...c, _chunk_types: ['identidad','conocimiento','personalidad','ejemplo_positivo'] } }));

// Re-genera SOLO los chunks de FAQs
const body = $('Webhook omghat1').item.json.body;
const slug = body.agent_id;
const faqs = body.faqs || [];

if (faqs.length === 0) {
  return [{ json: { text: 'Sin FAQs configuradas', id: `faq_${slug}_empty`, tipo: 'faq', categoria: 'faq', relevancia: 0.5, _chunk_types: ['faq'] } }];
}

return faqs.filter(f => f.question && f.answer && f.answer.length > 2).map((faq, i) => ({
  json: {
    text: `PREGUNTA FRECUENTE: ${faq.question} RESPUESTA: ${faq.answer}`,
    id: `faq_${slug}_${String(i+1).padStart(3,'0')}`,
    tipo: 'faq',
    categoria: 'faq',
    relevancia: 0.9,
    trigger_keywords: faq.question.toLowerCase().replace(/[¿?]/g, '').substring(0, 60),
    _chunk_types: ['faq']
  }
}));

// Re-genera SOLO los chunks de productos/rooms/menu
const body = $('Webhook omghat1').item.json.body;
const slug = body.agent_id;
const catalogType = body.catalog_type || 'products';
const items = body[catalogType] || body.products || body.rooms || body.menu || body.services || body.properties || [];
const images = body.images || [];

const chunks = [];

// Resumen de tarifas
if (items.length > 0) {
  const resumen = items.map(p => `${p.name}: $${p.price?.toLocaleString?.() ?? p.price}`).join('. ');
  chunks.push({
    text: `TARIFAS Y PRECIOS: ${resumen}`,
    id: `producto_tarifas_${slug}_001`,
    tipo: 'producto',
    categoria: 'producto',
    relevancia: 1.0,
    trigger_keywords: 'precio,tarifa,cuánto,cuesta,valor'
  });
}

// Chunk por item
items.forEach((item, i) => {
  let text = `${catalogType.toUpperCase()}: ${item.name}`;
  if (item.description) text += `. ${item.description}`;
  if (item.price) text += `. Precio: $${item.price?.toLocaleString?.() ?? item.price}`;
  if (item.category) text += `. Categoría: ${item.category}`;

  chunks.push({
    text,
    id: `producto_${slug}_${String(i+1).padStart(3,'0')}`,
    tipo: 'producto',
    categoria: 'producto',
    relevancia: 0.95,
    trigger_keywords: item.name.toLowerCase()
  });

  // Imagen principal
  if (item.image_url) {
    chunks.push({
      text: `IMAGEN DISPONIBLE: ${item.name}. Para enviar: [IMG:${item.image_url}]`,
      id: `media_img_${slug}_${String(i+1).padStart(3,'0')}`,
      tipo: 'media',
      categoria: 'media_imagen',
      relevancia: 0.9,
      trigger_keywords: `${item.name.toLowerCase()},foto,imagen,ver`
    });
  }

  // Variantes (imágenes adicionales)
  if (item.variants && Array.isArray(item.variants)) {
    item.variants.forEach((v, vi) => {
      if (!v.url) return;
      chunks.push({
        text: `IMAGEN ${v.title || 'adicional'} de ${item.name}. Para enviar: [IMG:${v.url}]`,
        id: `media_var_${slug}_${String(i+1).padStart(3,'0')}_${String(vi+1).padStart(2,'0')}`,
        tipo: 'media',
        categoria: 'media_imagen',
        relevancia: 0.85,
        trigger_keywords: `${(v.title || '').toLowerCase()},${item.name.toLowerCase()},foto`
      });
    });
  }
});

const chunkTypes = ['producto','media'];
return chunks.map(c => ({ json: { ...c, _chunk_types: chunkTypes } }));

const body = $('Webhook omghat1').item.json.body;
return [{
  json: {
    agent_id: body.agent_id,
    escalation_phone: body.escalation_phone ?? '',
    admin_phone: body.admin_phone ?? '',
    phones_list: [body.escalation_phone, body.admin_phone].filter((v, i, a) => v && a.indexOf(v) === i)
  }
}];
